package school.sptech;import java.time.LocalDateTime;import java.time.LocalTime;import java.time.format.DateTimeFormatter;import java.util.concurrent.ThreadLocalRandom;public class log {    public static void main(String[] args) throws InterruptedException {        String nivel = "";        String modulo = "";        String mensagem = "";        Integer numParaMensagem = -1;        DateTimeFormatter horaFormatada = DateTimeFormatter.ofPattern("dd/MM/yyyy HH:mm:ss");        while (true) {            LocalDateTime dataEHora = LocalDateTime.now();            numParaMensagem = ThreadLocalRandom.current().nextInt(1,7);            switch (numParaMensagem){                case 1:                    nivel = " ERROR ";                    modulo = " Dashboard ";                    mensagem = " Erro ao conectar com o banco de dados ";                    System.out.println("[" + dataEHora.format(horaFormatada) + "] |" + nivel + "|" + modulo + "|" + mensagem);                    break;                case 2:                    nivel = " INFO ";                    modulo = " Dashboard ";                    mensagem = " Conexão com o banco de dados relaizada com sucesso ";                    System.out.println("[" + dataEHora.format(horaFormatada) + "] |" + nivel + "|" + modulo + "|" + mensagem);                    break;                case 3:                    nivel = " WARNING ";                    modulo = " Dashboard ";                    mensagem = " Alguns dados não estão sincronizados com o banco de dados ";                    System.out.println("[" + dataEHora.format(horaFormatada) + "] |" + nivel + "|" + modulo + "|" + mensagem);                    break;                case 4:                    nivel = " ERROR ";                    modulo = " Operação CRUD ";                    mensagem = " Não foi possível alterar o nome do usuário ";                    System.out.println("[" + dataEHora.format(horaFormatada) + "] |" + nivel + "|" + modulo + "|" + mensagem);                    break;                case 5:                    nivel = " INFO ";                    modulo = " Operação CRUD ";                    mensagem = " Foto de perfil do usuário alterada com sucesso ";                    System.out.println("[" + dataEHora.format(horaFormatada) + "] |" + nivel + "|" + modulo + "|" + mensagem);                    break;                case 6:                    nivel = " WARNING ";                    modulo = " Operação CRUD ";                    mensagem = " Os dados alterados não estão sincronizados com o banco de dados ";                    System.out.println("[" + dataEHora.format(horaFormatada) + "] |" + nivel + "|" + modulo + "|" + mensagem);                    break;            }            Thread.sleep(5000);        }    }}